  1→/**
  2→ * Knowledge Base Validation Tests - TEA Module
  3→ *
  4→ * Tests tea-index.csv parsing, fragment existence, tag selection,
  5→ * and cross-fragment link references.
  6→ *
  7→ * Usage: node test/test-knowledge-base.js
  8→ */
  9→
 10→const fs = require('node:fs');
 11→const path = require('node:path');
 12→const { parse } = require('csv-parse/sync');
 13→
 14→// ANSI colors
 15→const colors = {
 16→  reset: '\u001B[0m',
 17→  green: '\u001B[32m',
 18→  red: '\u001B[31m',
 19→  yellow: '\u001B[33m',
 20→  cyan: '\u001B[36m',
 21→  dim: '\u001B[2m',
 22→};
 23→
 24→let passed = 0;
 25→let failed = 0;
 26→let warned = 0;
 27→
 28→function assert(condition, testName, errorMessage = '') {
 29→  if (condition) {
 30→    console.log(`${colors.green}✓${colors.reset} ${testName}`);
 31→    passed++;
 32→  } else {
 33→    console.log(`${colors.red}✗${colors.reset} ${testName}`);
 34→    if (errorMessage) {
 35→      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
 36→    }
 37→    failed++;
 38→  }
 39→}
 40→
 41→function warn(message) {
 42→  console.log(`${colors.yellow}•${colors.reset} ${message}`);
 43→  warned++;
 44→}
 45→
 46→function parseTags(tagString) {
 47→  if (!tagString) return [];
 48→  return tagString
 49→    .split(',')
 50→    .map((tag) => tag.trim())
 51→    .filter(Boolean);
 52→}
 53→
 54→function isExternalLink(href) {
 55→  return href.startsWith('http://') || href.startsWith('https://');
 56→}
 57→
 58→function resolveFragmentLink(baseDir, href) {
 59→  if (href.startsWith('knowledge/')) {
 60→    return path.join(baseDir, href);
 61→  }
 62→  if (href.startsWith('./') || href.startsWith('../')) {
 63→    return path.join(baseDir, href);
 64→  }
 65→  // If only a filename is provided, assume knowledge dir
 66→  if (href.endsWith('.md') && !href.includes('/')) {
 67→    return path.join(baseDir, 'knowledge', href);
 68→  }
 69→  return null;
 70→}
 71→
 72→function runTests() {
 73→  console.log(`${colors.cyan}========================================`);
 74→  console.log('TEA Knowledge Base Tests');
 75→  console.log(`========================================${colors.reset}\n`);
 76→
 77→  const projectRoot = path.join(__dirname, '..');
 78→  const kbRoot = path.join(projectRoot, 'src', 'testarch');
 79→  const indexPath = path.join(kbRoot, 'tea-index.csv');
 80→
 81→  // ============================================================
 82→  // Test 1: Parse CSV and validate structure
 83→  // ============================================================
 84→  console.log(`${colors.yellow}Test Suite 1: CSV Structure${colors.reset}\n`);
 85→
 86→  let records = [];
 87→  try {
 88→    const csv = fs.readFileSync(indexPath, 'utf8');
 89→    records = parse(csv, { columns: true, skip_empty_lines: true });
 90→
 91→    assert(records.length === 40, 'tea-index.csv has 40 fragment records', `Found ${records.length}`);
 92→
 93→    const requiredFields = ['id', 'name', 'description', 'tags', 'tier', 'fragment_file'];
 94→    const missingFields = requiredFields.filter((field) => !Object.prototype.hasOwnProperty.call(records[0] || {}, field));
 95→    assert(missingFields.length === 0, 'tea-index.csv has required columns', missingFields.join(', '));
 96→
 97→    // Validate tier values
 98→    const validTiers = new Set(['core', 'extended', 'specialized']);
 99→    const invalidTiers = records.filter((r) => !validTiers.has(r.tier));
100→    assert(
101→      invalidTiers.length === 0,
102→      'All fragments have valid tier values (core/extended/specialized)',
103→      invalidTiers.map((r) => `${r.id}: "${r.tier}"`).join(', '),
104→    );
105→  } catch (error) {
106→    assert(false, 'tea-index.csv parsed successfully', error.message);
107→  }
108→
109→  console.log('');
110→
111→  // ============================================================
112→  // Test 2: Fragment file existence
113→  // ============================================================
114→  console.log(`${colors.yellow}Test Suite 2: Fragment Existence${colors.reset}\n`);
115→
116→  if (records.length > 0) {
117→    let missingCount = 0;
118→    for (const record of records) {
119→      const fragmentPath = path.join(kbRoot, record.fragment_file);
120→      const exists = fs.existsSync(fragmentPath);
121→      if (!exists) missingCount++;
122→      assert(exists, `fragment exists: ${record.fragment_file}`);
123→    }
124→    assert(missingCount === 0, 'all fragments exist');
125→  } else {
126→    assert(false, 'fragment records loaded', 'No records found in tea-index.csv');
127→  }
128→
129→  console.log('');
130→
131→  // ============================================================
132→  // Test 3: Tag selection logic
133→  // ============================================================
134→  console.log(`${colors.yellow}Test Suite 3: Tag Selection${colors.reset}\n`);
135→
136→  if (records.length > 0) {
137→    const firstTag = parseTags(records[0].tags)[0];
138→    const selected = records.filter((record) => parseTags(record.tags).includes(firstTag));
139→    assert(Boolean(firstTag), 'first record has at least one tag');
140→    assert(selected.length > 0, `tag filter returns results for '${firstTag}'`);
141→
142→    const none = records.filter((record) => parseTags(record.tags).includes('__no_such_tag__'));
143→    assert(none.length === 0, 'unknown tag returns no results');
144→  } else {
145→    assert(false, 'tag selection tested', 'No records to test');
146→  }
147→
148→  console.log('');
149→
150→  // ============================================================
151→  // Test 4: Cross-fragment references
152→  // ============================================================
153→  console.log(`${colors.yellow}Test Suite 4: Cross-Fragment Links${colors.reset}\n`);
154→
155→  const knowledgeDir = path.join(kbRoot, 'knowledge');
156→  const mdFiles = fs.readdirSync(knowledgeDir).filter((name) => name.endsWith('.md'));
157→
158→  let linkCount = 0;
159→  let brokenLinks = 0;
160→
161→  for (const fileName of mdFiles) {
162→    const filePath = path.join(knowledgeDir, fileName);
163→    const content = fs.readFileSync(filePath, 'utf8');
164→
165→    const linkMatches = content.matchAll(/\]\(([^)]+)\)/g);
166→    for (const match of linkMatches) {
167→      const href = match[1].trim();
168→      if (!href.endsWith('.md') || isExternalLink(href)) continue;
169→
170→      const resolved = resolveFragmentLink(kbRoot, href);
171→      if (!resolved) continue;
172→
173→      linkCount++;
174→      const exists = fs.existsSync(resolved);
175→      if (!exists) brokenLinks++;
176→      assert(exists, `link resolves: ${fileName} -> ${href}`);
177→    }
178→  }
179→
180→  if (linkCount === 0) {
181→    warn('no cross-fragment links detected (informational)');
182→  } else {
183→    assert(linkCount > 0, 'cross-fragment links detected (at least one)');
184→  }
185→  assert(brokenLinks === 0, 'no broken cross-fragment links');
186→
187→  console.log('');
188→
189→  // ============================================================
190→  // Summary
191→  // ============================================================
192→  console.log(`${colors.cyan}========================================`);
193→  console.log('Test Results:');
194→  console.log(`  Passed: ${colors.green}${passed}${colors.reset}`);
195→  console.log(`  Warnings: ${colors.yellow}${warned}${colors.reset}`);
196→  console.log(`  Failed: ${colors.red}${failed}${colors.reset}`);
197→  console.log(`========================================${colors.reset}\n`);
198→
199→  if (failed === 0) {
200→    console.log(`${colors.green}✨ Knowledge base tests passed!${colors.reset}\n`);
